import{a as i}from"./api-RY2-2DBj.js";const u={async getAllNotifications(){try{const e=[];try{((await i.get("/roomapplications")).data||[]).filter(t=>t.status==="Pending").forEach(t=>{e.push({id:`app-${t.id}`,type:"room_application",title:"Đơn đăng ký phòng mới",description:`${t.studentName||"Sinh viên"} đã đăng ký phòng`,time:new Date(t.submittedDate||Date.now()),link:"/admin/room-applications",unread:!0,priority:"normal"})})}catch(n){console.error("Error fetching room applications:",n)}try{((await i.get("/maintenancerequests")).data||[]).filter(t=>t.status==="Pending").forEach(t=>{e.push({id:`maint-${t.id}`,type:"maintenance_request",title:"Yêu cầu sửa chữa mới",description:`Phòng ${t.roomNumber||"N/A"}: ${t.description||"Yêu cầu sửa chữa"}`,time:new Date(t.requestDate||Date.now()),link:"/admin/maintenance-requests",unread:!0,priority:t.priority==="Urgent"?"high":"normal"})})}catch(n){console.error("Error fetching maintenance requests:",n)}try{((await i.get("/contracts")).data||[]).filter(t=>t.status==="Active"&&new Date(t.startDate)>new Date(Date.now()-7*24*60*60*1e3)).forEach(t=>{e.push({id:`contract-${t.id}`,type:"contract_approved",title:"Hợp đồng được chấp thuận",description:`Hợp đồng phòng ${t.roomNumber||"N/A"} đã được kích hoạt`,time:new Date(t.startDate||Date.now()),link:"/admin/contracts",unread:!1,priority:"low"})})}catch(n){console.error("Error fetching contracts:",n)}try{((await i.get("/contracts")).data||[]).filter(t=>{if(t.status!=="Active")return!1;const a=new Date(t.endDate),s=Math.floor((a-new Date)/(1e3*60*60*24));return s>0&&s<=30}).forEach(t=>{const a=Math.floor((new Date(t.endDate)-new Date)/864e5);e.push({id:`expiring-${t.id}`,type:"contract_expiring",title:"Hợp đồng sắp hết hạn",description:`Hợp đồng phòng ${t.roomNumber||"N/A"} còn ${a} ngày`,time:new Date(t.endDate||Date.now()),link:"/admin/contracts",unread:!0,priority:a<=7?"high":"normal"})})}catch(n){console.error("Error fetching expiring contracts:",n)}try{((await i.get("/contractextensions")).data||[]).filter(t=>t.status==="Pending").forEach(t=>{e.push({id:`ext-${t.id}`,type:"contract_extension",title:"Yêu cầu gia hạn hợp đồng",description:`Yêu cầu gia hạn ${t.extensionMonths||0} tháng`,time:new Date(t.requestDate||Date.now()),link:"/admin/contract-extensions",unread:!0,priority:"normal"})})}catch(n){console.error("Error fetching contract extensions:",n)}try{((await i.get("/roomtransfers")).data||[]).filter(t=>t.status==="Pending").forEach(t=>{e.push({id:`transfer-${t.id}`,type:"room_transfer",title:"Yêu cầu chuyển phòng",description:`Chuyển từ phòng ${t.fromRoomNumber||"N/A"} sang ${t.toRoomNumber||"N/A"}`,time:new Date(t.requestDate||Date.now()),link:"/admin/room-transfers",unread:!0,priority:"normal"})})}catch(n){console.error("Error fetching room transfers:",n)}return e.sort((n,o)=>{const r={high:3,normal:2,low:1};return r[n.priority]!==r[o.priority]?r[o.priority]-r[n.priority]:o.time-n.time}),e}catch(e){return console.error("Error getting notifications:",e),[]}},async getUnreadCount(){try{return(await this.getAllNotifications()).filter(n=>n.unread).length}catch(e){return console.error("Error getting unread count:",e),0}}};export{u as n};
